document.addEventListener('DOMContentLoaded', () => {
const navbar = document.getElementById('navbar');
window.addEventListener('scroll', () => {
if (navbar) navbar.classList.toggle('scrolled', window.scrollY > 60);
}, { passive: true });
const hamburger = document.getElementById('hamburger');
const navLinks = document.getElementById('navLinks');
if (hamburger && navLinks) {
const focusableSelectors = 'a[href], button:not([disabled])';
const openMenu = () => {
navLinks.classList.add('open');
hamburger.setAttribute('aria-expanded', 'true');
const first = navLinks.querySelector(focusableSelectors);
if (first) first.focus();
};
const closeMenu = () => {
navLinks.classList.remove('open');
hamburger.setAttribute('aria-expanded', 'false');
hamburger.focus();
};
hamburger.addEventListener('click', () => {
navLinks.classList.contains('open') ? closeMenu() : openMenu();
});
navLinks.querySelectorAll('a').forEach(link => {
link.addEventListener('click', closeMenu);
});
document.addEventListener('click', (e) => {
if (!navbar.contains(e.target)) closeMenu();
});
navLinks.addEventListener('keydown', (e) => {
if (!navLinks.classList.contains('open')) return;
if (e.key === 'Escape') { closeMenu(); return; }
if (e.key !== 'Tab') return;
const focusable = Array.from(navLinks.querySelectorAll(focusableSelectors));
const first = focusable[0];
const last = focusable[focusable.length - 1];
if (e.shiftKey && document.activeElement === first) {
e.preventDefault();
last.focus();
} else if (!e.shiftKey && document.activeElement === last) {
e.preventDefault();
first.focus();
}
});
document.addEventListener('keydown', (e) => {
if (e.key === 'Escape' && navLinks.classList.contains('open')) closeMenu();
});
}
(function () {
const path = window.location.pathname;
const page = path.split('/').pop().replace('.html', '') || 'index';
const pageMap = { index: 'index', work: 'work', about: 'about', contact: 'contact' };
const current = pageMap[page];
if (current) {
document.querySelectorAll('.nav-links a[data-page]').forEach(link => {
if (link.dataset.page === current && !link.classList.contains('nav-cta')) {
link.classList.add('nav-active');
}
});
}
})();
const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
document.querySelectorAll('a[href^="#"]').forEach(anchor => {
anchor.addEventListener('click', function (e) {
const target = document.querySelector(this.getAttribute('href'));
if (target) {
e.preventDefault();
const offset = navbar ? navbar.offsetHeight + 16 : 16;
window.scrollTo({
top: target.getBoundingClientRect().top + window.scrollY - offset,
behavior: prefersReducedMotion ? 'auto' : 'smooth',
});
}
});
});
const revealEls = document.querySelectorAll('.reveal');
if (revealEls.length) {
if (prefersReducedMotion) {
revealEls.forEach(el => el.classList.add('visible'));
} else {
const revealObs = new IntersectionObserver((entries) => {
entries.forEach(entry => {
if (entry.isIntersecting) {
entry.target.classList.add('visible');
revealObs.unobserve(entry.target);
}
});
}, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });
revealEls.forEach(el => revealObs.observe(el));
}
}
const statEls = document.querySelectorAll('.stat-number[data-target]');
if (statEls.length) {
if (prefersReducedMotion) {
statEls.forEach(el => {
const prefix = el.dataset.prefix || '';
const suffix = el.dataset.suffix || '';
el.textContent = prefix + parseInt(el.dataset.target, 10).toLocaleString('en-GB') + suffix;
});
} else {
const counterObs = new IntersectionObserver((entries) => {
entries.forEach(entry => {
if (!entry.isIntersecting) return;
const el = entry.target;
const target = parseInt(el.dataset.target, 10);
const prefix = el.dataset.prefix || '';
const suffix = el.dataset.suffix || '';
const duration = 1400;
const step = 16;
const steps = Math.floor(duration / step);
let current = 0;
const inc = target / steps;
const timer = setInterval(() => {
current += inc;
if (current >= target) { current = target; clearInterval(timer); }
el.textContent = prefix + Math.floor(current).toLocaleString('en-GB') + suffix;
}, step);
counterObs.unobserve(el);
});
}, { threshold: 0.5 });
statEls.forEach(el => counterObs.observe(el));
}
}
const floatCta = document.getElementById('floatCta');
const floatLink = document.getElementById('floatCtaLink');
const heroEl = document.getElementById('hero');
if (floatCta && heroEl) {
const setVisible = (visible) => {
floatCta.style.opacity = visible ? '1' : '0';
floatCta.style.pointerEvents = visible ? 'auto' : 'none';
if (floatLink) {
floatLink.setAttribute('tabindex', visible ? '0' : '-1');
floatLink.setAttribute('aria-hidden', visible ? 'false' : 'true');
}
};
const floatObs = new IntersectionObserver((entries) => {
entries.forEach(entry => setVisible(!entry.isIntersecting));
}, { threshold: 0.1 });
floatObs.observe(heroEl);
floatCta.style.transition = 'opacity 0.4s ease';
setVisible(false);
}
const faqItems = document.querySelectorAll('.faq-item');
faqItems.forEach(item => {
const question = item.querySelector('.faq-question');
if (!question) return;
const toggle = () => {
const isOpen = item.classList.contains('open');
faqItems.forEach(other => {
other.classList.remove('open');
const q = other.querySelector('.faq-question');
if (q) q.setAttribute('aria-expanded', 'false');
});
if (!isOpen) {
item.classList.add('open');
question.setAttribute('aria-expanded', 'true');
}
};
question.addEventListener('click', toggle);
question.addEventListener('keydown', (e) => {
if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggle(); }
});
});
(function () {
const outer = document.getElementById('testimonialsOuter');
const grid = document.getElementById('testimonialsGrid');
const dots = document.querySelectorAll('.t-dot');
if (!outer || !grid) return;
const ORIGINALS = Array.from(grid.querySelectorAll('.testimonial-card'));
const TOTAL = ORIGINALS.length;
const GAP = 24;
const SPEED = prefersReducedMotion ? 0 : 4000;
const DUR = prefersReducedMotion ? 0 : 520;
let perView = 3, cardW = 0, stepW = 0, current = 0, timer = null, busy = false;
function buildTrack() {
grid.innerHTML = '';
const before = ORIGINALS.slice(-TOTAL).map(n => { const cl = n.cloneNode(true); cl.setAttribute('aria-hidden', 'true'); return cl; });
const after = ORIGINALS.slice(0, TOTAL).map(n => { const cl = n.cloneNode(true); cl.setAttribute('aria-hidden', 'true'); return cl; });
before.forEach(n => grid.appendChild(n));
ORIGINALS.forEach(n => grid.appendChild(n.cloneNode(true)));
after.forEach(n => grid.appendChild(n));
}
function measure() {
const outerW = outer.offsetWidth;
perView = window.innerWidth <= 768 ? 1 : 3;
cardW = (outerW - GAP * (perView - 1)) / perView;
stepW = cardW + GAP;
const allCards = Array.from(grid.querySelectorAll('.testimonial-card'));
allCards.forEach(c => { c.style.width = cardW + 'px'; c.style.flexShrink = '0'; });
grid.style.gap = GAP + 'px';
snapTo(current);
}
function snapTo(idx) {
const pos = TOTAL + idx;
grid.style.transition = 'none';
grid.style.transform = `translateX(-${pos * stepW}px)`;
updateDots(idx);
void grid.offsetWidth;
}
function slideTo(nextIdx) {
if (busy) return;
busy = true;
let animateToPos;
if (nextIdx === 0 && current === TOTAL - 1) animateToPos = TOTAL * 2;
else if (nextIdx === TOTAL - 1 && current === 0) animateToPos = TOTAL - 1;
else animateToPos = TOTAL + nextIdx;
grid.style.transition = `transform ${DUR}ms cubic-bezier(0.4,0,0.2,1)`;
grid.style.transform = `translateX(-${animateToPos * stepW}px)`;
updateDots(nextIdx);
setTimeout(() => { current = nextIdx; snapTo(current); busy = false; }, DUR + 16);
}
function advance() { slideTo((current + 1) % TOTAL); }
function updateDots(idx) {
dots.forEach((d, i) => d.classList.toggle('active', i === idx));
}
function startAuto() {
clearInterval(timer);
if (SPEED > 0) timer = setInterval(advance, SPEED);
}
dots.forEach((dot, i) => {
dot.addEventListener('click', () => { if (busy) return; current = i; snapTo(i); startAuto(); });
});
outer.addEventListener('keydown', (e) => {
if (e.key === 'ArrowLeft') { slideTo((current - 1 + TOTAL) % TOTAL); startAuto(); }
if (e.key === 'ArrowRight') { slideTo((current + 1) % TOTAL); startAuto(); }
});
outer.setAttribute('tabindex', '0');
outer.setAttribute('role', 'region');
outer.setAttribute('aria-label', 'Client testimonials');
outer.addEventListener('mouseenter', () => clearInterval(timer));
outer.addEventListener('mouseleave', startAuto);
let touchStartX = 0;
outer.addEventListener('touchstart', (e) => { touchStartX = e.touches[0].clientX; }, { passive: true });
outer.addEventListener('touchend', (e) => {
const diff = touchStartX - e.changedTouches[0].clientX;
if (Math.abs(diff) > 44) {
slideTo(diff > 0 ? (current + 1) % TOTAL : (current - 1 + TOTAL) % TOTAL);
startAuto();
}
}, { passive: true });
let resizeTimer;
window.addEventListener('resize', () => {
clearTimeout(resizeTimer);
resizeTimer = setTimeout(() => { buildTrack(); measure(); startAuto(); }, 150);
}, { passive: true });
buildTrack(); measure(); startAuto();
})();
const banner = document.getElementById('cookie-banner');
const accept = document.getElementById('cookieAccept');
const decline = document.getElementById('cookieDecline');
if (banner) {
const consent = localStorage.getItem('hs_cookie_consent');
if (!consent) {
setTimeout(() => {
banner.classList.add('visible');
banner.setAttribute('aria-live', 'polite');
}, 1200);
} else {
const fc = document.getElementById('floatCta');
if (fc) fc.classList.add('cookie-dismissed');
}
const dismiss = (value) => {
banner.classList.remove('visible');
try { localStorage.setItem('hs_cookie_consent', value); } catch {}
const fc = document.getElementById('floatCta');
if (fc) fc.classList.add('cookie-dismissed');
};
if (accept) accept.addEventListener('click', () => dismiss('accepted'));
if (decline) decline.addEventListener('click', () => dismiss('declined'));
}
});